mapper.select:
SELECT CAST(file_rows.id AS CHAR) AS id, file_rows.bizType AS bizType, CAST(file_rows.bizId AS CHAR) AS bizId, file_rows.originalName AS originalName, file_rows.operatorName AS operatorName, DATE_FORMAT(file_rows.uploadTime, '%Y-%m-%d %H:%i:%s') AS uploadTime FROM ( SELECT f.id, f.biz_type AS bizType, f.biz_id AS bizId, f.original_name AS originalName, COALESCE(u.nick_name, u.username, '') AS operatorName, f.upload_time AS uploadTime FROM file_storage f LEFT JOIN sys_user u ON u.id = f.uploader_id WHERE f.biz_type IN ('ORDER_CONTRACT', 'ORDER_PAYMENT', 'ORDER_SHIPMENT') AND f.biz_id = #{orderId}
UNION ALL
SELECT f.id, f.biz_type AS bizType, f.biz_id AS bizId, f.original_name AS originalName, COALESCE(u.nick_name, u.username, '') AS operatorName, f.upload_time AS uploadTime FROM file_storage f JOIN aftersale_info a ON a.id = f.biz_id AND a.deleted = 0 LEFT JOIN sys_user u ON u.id = f.uploader_id WHERE f.biz_type IN ('AFTERSALE_APPLY', 'AFTERSALE_RETURN', 'AFTERSALE_REFUND') AND a.order_id = #{orderId} ) file_rows ORDER BY file_rows.uploadTime DESC, file_rows.id DESC
